catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading || newValue == '') {
        return;
    }
	// Split it by the space to grab just the date portion: "2026-04-15"
    var dateString = newValue.split(' ')[0]; 

    // 2. Split the date portion by the hyphen into Year, Month, Day
    var dateParts = dateString.split('-');
    var year = parseInt(dateParts[0], 10);
    var month = parseInt(dateParts[1], 10) - 1; // JS months are 0-indexed (0-11)
    var day = parseInt(dateParts[2], 10);

    // 3. Construct a safe Date object that won't break in the browser
    var selectedDate = new Date(year, month, day);

    // 4. Get today's date and set it to exactly midnight
    var today = new Date();
    today.setHours(0, 0, 0, 0);

    // 5. Run the comparison
    if (selectedDate < today) {
		// Throw a prominent red error banner at the top of the form
        g_form.addErrorMessage('The deadline cannot be in the past. Please select a future date.');
		// Clear the value
        g_form.clearValue('due_date');
    } else {
		// Clear any existing error banners if they pick a good date
        g_form.clearMessages();
    }
}
